Javascript.validate:
			//Validation: only numeric characters allowed and two decimal places.
			//Error message: Currency amounts must be in the format of 0.00
			//Currency field. Max value. 99999999.99
            var value = Services.getValue(BasicInCourt.dataBinding);      
          	var maxVal = 99999999.99;         
          	var err = null;
          
          	if( '0.00 ' != value )
          	{   err = validateCurrencyValue(value, maxVal);
              if( null == err)
              { 
                var returnVal = WPU.formatToTwoDP(value);
                Services.setValue(BasicInCourt.dataBinding, returnVal);
              } 
          	}
          	return err;

Javascript.transformToModel:

  if( null == value || "" == value )
  {  return "0.00 ";
  }
  else
  { return value;
  }

